using Ledgerly.Application.Abstractions; using Ledgerly.Application.Expenses; using Ledgerly.Application.Journals; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Application.Tests; public class ExpenseServiceTests { static readonly Guid Org=Guid.NewGuid(); [Fact] public async Task PostAsync_posts_journal(){ var a=new InMemoryAccountRepository(); var j=new InMemoryJournalRepository(); var c=new InMemoryContactRepository(); var t=new InMemoryTaxCodeRepository(); var e=new InMemoryExpenseRepository(); var svc=new ExpenseService(e,c,t,new JournalService(j, a, new InMemoryFiscalPeriodRepository())); var exp=new Account(Org,"5000","Exp",AccountType.Expense,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); var cash=new Account(Org,"1000","Cash",AccountType.Asset,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); await a.AddAsync(exp); await a.AddAsync(cash); var created=await svc.CreateAsync(new CreateExpenseRequest(Org,"Office supplies",new DateOnly(2026,3,1),"USD",75m,exp.Id,cash.Id,null,null,null)); var posted=await svc.PostAsync(Org,created.Value!.Id); Assert.True(posted.IsSuccess); Assert.Equal(ExpenseStatus.Posted,posted.Value!.Status); Assert.NotNull(posted.Value.JournalEntryId);} [Fact] public async Task SetReceiptAsync_updates_receipt(){ var e=new InMemoryExpenseRepository(); var svc=new ExpenseService(e,new InMemoryContactRepository(),new InMemoryTaxCodeRepository(),new JournalService(new InMemoryJournalRepository(), new InMemoryAccountRepository(), new InMemoryFiscalPeriodRepository())); var created=await svc.CreateAsync(new CreateExpenseRequest(Org,"Travel",new DateOnly(2026,3,1),"USD",120m,Guid.NewGuid(),Guid.NewGuid(),null,null,null)); var updated=await svc.SetReceiptAsync(Org,created.Value!.Id,new SetExpenseReceiptRequest("https://example.com/receipt.pdf")); Assert.True(updated.IsSuccess); Assert.Equal("https://example.com/receipt.pdf",updated.Value!.ReceiptUrl);} sealed class InMemoryExpenseRepository:IExpenseRepository{List<Expense> _l=new(); public Task<Expense?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<Expense>> ListByOrganizationAsync(Guid o,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Expense>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task AddAsync(Expense expense,CancellationToken ct=default){_l.Add(expense);return Task.CompletedTask;} public Task UpdateAsync(Expense expense,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryTaxCodeRepository:ITaxCodeRepository{List<TaxCode> _l=new(); public Task<TaxCode?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<TaxCode?> GetByCodeAsync(Guid o,string code,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Code==code)); public Task<IReadOnlyList<TaxCode>> ListByOrganizationAsync(Guid o,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<TaxCode>>(_l.Where(x=>x.OrganizationId==o&&(!ia?!x.IsArchived:true)).OrderBy(x=>x.Code).ToList()); public Task AddAsync(TaxCode t,CancellationToken ct=default){_l.Add(t);return Task.CompletedTask;} public Task UpdateAsync(TaxCode t,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryContactRepository:IContactRepository{List<Contact> _l=new(); public Task<Contact?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<Contact>> ListByTypeAsync(Guid o,ContactType t,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Contact>>(_l.Where(x=>x.OrganizationId==o&&x.ContactType==t).ToList()); public Task AddAsync(Contact c,CancellationToken ct=default){_l.Add(c);return Task.CompletedTask;} public Task UpdateAsync(Contact c,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryJournalRepository:IJournalRepository{List<JournalEntry> _l=new(); public Task<JournalEntry?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<JournalEntry>> ListByOrganizationAsync(Guid o,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<JournalEntry>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>> ListPostedLinesByAccountAsync(Guid o,Guid a,DateOnly s,DateOnly e,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>>(_l.Where(x=>x.OrganizationId==o&&x.Status==JournalEntryStatus.Posted&&x.EntryDate>=s&&x.EntryDate<=e).SelectMany(x=>x.Lines.Where(l=>l.AccountId==a).Select(l=>(x,l))).ToList()); public Task<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>> ListPostedLinesAsync(Guid o,DateOnly? s,DateOnly e,CancellationToken ct=default){var q=_l.Where(x=>x.OrganizationId==o&&x.Status==JournalEntryStatus.Posted&&x.EntryDate<=e);if(s.HasValue)q=q.Where(x=>x.EntryDate>=s.Value);return Task.FromResult<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>>(q.SelectMany(x=>x.Lines.Select(l=>(x,l))).ToList());} public Task AddAsync(JournalEntry e,CancellationToken ct=default){_l.Add(e);return Task.CompletedTask;} public Task UpdateAsync(JournalEntry e,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryAccountRepository:IAccountRepository{List<Account> _l=new(); public Task<Account?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<Account?> GetByCodeAsync(Guid o,string code,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Code==code)); public Task<IReadOnlyList<Account>> ListByOrganizationAsync(Guid o,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task<IReadOnlyList<Account>> GetChildrenAsync(Guid o,Guid p,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(Array.Empty<Account>()); public Task<bool> HasActiveChildrenAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(false); public Task AddAsync(Account a,CancellationToken ct=default){_l.Add(a);return Task.CompletedTask;} public Task UpdateAsync(Account a,CancellationToken ct=default)=>Task.CompletedTask;} }
